// Services/ReportsService.cs
using Microsoft.EntityFrameworkCore;
using KmgAssets.Data;
using KmgAssets.Dtos;

namespace KmgAssets.Services;

public sealed class ReportsService
{
    private readonly Func<KmgDbContext> _dbFactory;
    public ReportsService(Func<KmgDbContext> dbFactory) => _dbFactory = dbFactory;

    public async Task<List<AssetUtilizationDto>> GetUtilizationAsync(
        int? departmentId, DateTime from, DateTime to, CancellationToken ct = default)
    {
        using var db = _dbFactory();
        return await db.AssetUtilization
            .FromSqlInterpolated(
                $"EXEC dbo.sp_GetAssetUtilization @DepartmentId={departmentId}, @FromDate={from.Date}, @ToDate={to.Date}")
            .AsNoTracking()
            .ToListAsync(ct);
    }
}

// Services/ExcelExporter.cs
using ClosedXML.Excel;
using KmgAssets.Dtos;

namespace KmgAssets.Services;

public static class ExcelExporter
{
    public static byte[] BuildUtilizationReport(IReadOnlyList<AssetUtilizationDto> rows)
    {
        using var wb = new XLWorkbook();
        var ws = wb.Worksheets.Add("Utilization");

        string[] headers = { "Id", "Name", "Department", "Repairs", "Total Cost" };
        for (int i = 0; i < headers.Length; i++)
            ws.Cell(1, i + 1).Value = headers[i];
        ws.Range(1, 1, 1, headers.Length).Style.Font.Bold = true;

        for (int i = 0; i < rows.Count; i++)
        {
            var r = rows[i];
            int row = i + 2;
            ws.Cell(row, 1).Value = r.Id;
            ws.Cell(row, 2).Value = r.Name;
            ws.Cell(row, 3).Value = r.DepartmentName;
            ws.Cell(row, 4).Value = r.RepairCount;
            ws.Cell(row, 5).Value = r.TotalCost;
        }
        ws.Columns().AdjustToContents();

        using var ms = new MemoryStream();
        wb.SaveAs(ms);
        return ms.ToArray();
    }
}

// ViewModels/DashboardVM.cs
[RelayCommand]
private async Task ExportAsync(CancellationToken ct)
{
    var bytes = ExcelExporter.BuildUtilizationReport(Rows);
    using var stream = new MemoryStream(bytes);
    var result = await FileSaver.Default.SaveAsync(
        $"utilization-{DateTime.Now:yyyyMMdd-HHmm}.xlsx", stream, ct);

    if (result.IsSuccessful)
        await Shell.Current.DisplayAlert("Готово", $"Сохранено: {result.FilePath}", "OK");
    else
        await Shell.Current.DisplayAlert("Отмена", "Экспорт не выполнен", "OK");
}
